/* Aula 05 — modelJs: truthy/falsy e validações */

// 1) Truthy/Falsy na prática
console.log('0 ->', Boolean(0));
console.log("'0' ->", Boolean('0'));
console.log("'' ->", Boolean(''));
console.log('[] ->', Boolean([]));
console.log('{} ->', Boolean({}));

// 2) Texto: validar preenchido de verdade
let nome = '   ';
console.log('nome (cru) é truthy?', Boolean(nome));
console.log('nome (trim) é truthy?', Boolean(nome.trim()));

// 3) Número: 0 pode ser válido dependendo da regra
let idade = 0;
const idadeFoiInformada = idade !== null && idade !== undefined; // aceita 0
const idadeValida = idade > 0; // exige > 0
console.log('idadeFoiInformada:', idadeFoiInformada);
console.log('idadeValida:', idadeValida);

// 4) NaN
const valor = Number('10a');
console.log('valor:', valor);
console.log('isNaN:', Number.isNaN(valor));
